const fs = require\('fs'\);
const zlib = require\('zlib'\);

const buf = fs.readFileSync\('pedidos-GERAL.pdf'\);
const str = buf.toString\('binary'\);

// Find all FlateDecode streams and decompress them
const streamRe = /\\/Filter\\/FlateDecode[^>]*>>\\s*stream\\r?\\n\([\\s\\S]*?\)\\r?\\nendstream/g;
let match;
const texts = [];

while \(\(match = streamRe.exec\(str\)\) !== null\) {
  const raw = Buffer.from\(match[1], 'binary'\);
  try {
    const decompressed = zlib.inflateSync\(raw\).toString\('latin1'\);
    // Look for text containing letters \(likely RCA names\)
    if \(/[A-Za-záéíóúàâêôãõ]{5,}/.test\(decompressed\)\) {
      texts.push\(decompressed\);
    }
  } catch\(e\) {}
}

console.log\('Found', texts.length, 'text streams'\);
// Print first 3 streams
texts.slice\(0, 3\).forEach\(\(t, i\) => {
  console.log\('--- Stream', i+1, '---'\);
  console.log\(t.slice\(0, 2000\)\);
}\);
" 2>&1)

